using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class PostTools
{
    [McpServerTool, Description("Get a post by its ID from the REST API.")]
    public static async Task<string> GetPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric ID of the post to retrieve.")] int id)
    {
        using var client = httpClientFactory.CreateClient("api");
        var post = await client.GetFromJsonAsync<Post>($"/posts/{id}");
        return post is null
            ? $"Post {id} not found."
            : $"**{post.Title}**\n\n{post.Body}";
    }

    [McpServerTool, Description("List posts, optionally filtered by user ID.")]
    public static async Task<string> ListPosts(
        IHttpClientFactory httpClientFactory,
        [Description("Optional user ID to filter posts.")] int? userId = null)
    {
        using var client = httpClientFactory.CreateClient("api");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var posts = await client.GetFromJsonAsync<List<Post>>(url);
        if (posts is null || posts.Count == 0)
            return "No posts found.";

        return string.Join("\n", posts.Select(p => $"[{p.Id}] {p.Title}"));
    }

    [McpServerTool, Description("Create a new post.")]
    public static async Task<string> CreatePost(
        IHttpClientFactory httpClientFactory,
        [Description("The user ID authoring the post.")] int userId,
        [Description("The title of the post.")] string title,
        [Description("The body content of the post.")] string body)
    {
        using var client = httpClientFactory.CreateClient("api");
        var response = await client.PostAsJsonAsync("/posts", new { userId, title, body });
        response.EnsureSuccessStatusCode();
        var created = await response.Content.ReadFromJsonAsync<Post>();
        return $"Created post with ID {created?.Id}.";
    }
}

public record Post
{
    [JsonPropertyName("id")]
    public int Id { get; init; }

    [JsonPropertyName("userId")]
    public int UserId { get; init; }

    [JsonPropertyName("title")]
    public string Title { get; init; } = "";

    [JsonPropertyName("body")]
    public string Body { get; init; } = "";
}

